CREATE procedure [UpdateInheritPortalObjectPermissions] ( @objId bigint, -- это идентификатор объекта для которого нужно обновить привилегии @onlyChildren bit -- обновлять только в дочерних элементах ) as begin
-- маска начальников пользователя declare @usermask bigint; set @usermask = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 declare @objqueue table (id bigint, folder bigint, creationAuthor bigint);
with rec(Id, Folder, CreationAuthor) as ( select d.Id, d.Folder, d.CreationAuthor from PortalObject d where d.Id = @objId union all select dc.Id, dc.Folder, dc.CreationAuthor from PortalObject dc inner join rec on rec.Id = dc.Folder and dc.InheritPermissions = 1 ) insert into @objqueue (id, folder, creationAuthor) select * from rec where @onlyChildren = 0 or id != @objId
while((select COUNT(*) from @objqueue) > 0) begin declare @currentId bigint, @parentId bigint, @creationAuthor bigint; select top 1 @currentId = id, @parentId = folder, @creationAuthor = creationAuthor from @objqueue
if @parentId is not null begin -- TODO использовать merge для минимизации изменений! delete from PortalObjectPermission where PortalObject = @currentId and InheritedFromFolder is not null;
declare @insTable table ( [Id] [bigint] NOT NULL Primary KEY, [Uid] [uniqueidentifier] NULL, [PortalObject] [bigint] NULL, [PermissionId] [uniqueidentifier] NULL, [User] [bigint] NULL, [Group] [bigint] NULL, [OrganizationItemPosition] [bigint] NULL, [OrganizationItemEmployee] [bigint] NULL, [UserSecuritySetCacheId] [bigint] NULL, [PermissionRole] [uniqueidentifier] NULL, [InheritedFromFolder] [bigint] NULL );
declare @insCounter bigint, @insStartId bigint, @insEndId bigint;
insert into @insTable ( [Id], [Uid], PortalObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId ) select ROW_NUMBER() over (order by [Id]) - 1, NEWID(), @currentId, pdp.[Group], case when pdp.InheritedFromFolder is null then @parentId else pdp.InheritedFromFolder end, pdp.OrganizationItemEmployee, pdp.OrganizationItemPosition, pdp.PermissionId, pdp.PermissionRole, (case when pdp.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then @creationAuthor else pdp.[User] end) as [User], (case when pdp.PermissionRole = 'B4565CC1-7CB3-4201-B7BD-15872D1E7F92' then (@creationAuthor|@usermask) else pdp.UserSecuritySetCacheId end) as UserSecuritySetCacheId from PortalObjectPermission pdp where pdp.PortalObject = @parentId;
SELECT @insCounter = COUNT(Id) FROM @insTable;
EXECUTE [G_GenId] 'PortalObjectPermission', @insCounter, @insStartId out, @insEndId out;
insert into PortalObjectPermission ( [Id], [Uid], PortalObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId ) select @insStartId + [Id], [Uid], PortalObject, [Group], InheritedFromFolder, OrganizationItemEmployee, OrganizationItemPosition, PermissionId, PermissionRole, [User], UserSecuritySetCacheId from @insTable;
delete from @insTable;
end delete from @objqueue where id = @currentId; end end
